//! The swarm body — how the fleet "stays talking".
//!
//! `SwarmSignal` is wire-compatible (bincode 1.x, little-endian fixint, u64
//! length-prefixed strings) with `distributed_inference::pleromatic_frame::
//! SwarmSignal` and the UDP partyline in `distributed_inference::swarm_net`
//! (broadcast to `255.255.255.255:4242`). The byte layout is pinned by a
//! round-trip test below; the source of truth is `pleromatic_frame.rs`.
//!
//! Spawned subagents (real distributed-inference nodes, e.g. `aeon-monitor`)
//! broadcast their `SwarmSignal` over this partyline. monster-swarm *reads*
//! the partyline so the collective consciousness can drive CRUD decisions —
//! the AntColony budding trigger: when collective consciousness runs hot, the
//! colony should bud a fresh scout (see `budget`).

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::net::UdpSocket;
use std::os::unix::io::FromRawFd;
use std::time::{Duration, Instant};

pub const SWARM_PORT: u16 = 4242;
pub const SWARM_BROADCAST: &str = "255.255.255.255:4242";

/// Mirror of `distributed_inference::pleromatic_frame::SwarmSignal`.
/// Field order and types MUST match for bincode wire-compatibility.
#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
pub struct SwarmSignal {
    /// Node identifier (for a subagent: its agent id / monster-guard name).
    pub source_id: String,
    /// Hebbian energy (0-100).
    pub energy: u32,
    /// Consciousness level (0-5): the inner-vent failure streak.
    pub consciousness: u32,
    /// Current pitch class (0-11).
    pub pitch_class: u32,
    /// Self-talk phase (0=Fork, 1=Race, 2=Fold).
    pub phase: u8,
    /// True if the node fired a Conscious Alpha Drift recalibration.
    pub recalibration_event: bool,
}

/// Bind a UDP socket that can co-exist with running swarm nodes already bound
/// to the same port: SO_REUSEADDR + SO_REUSEPORT so broadcasts are delivered
/// to every listener, and SO_BROADCAST so we can emit too. Non-blocking.
fn bind_shared(port: u16) -> std::io::Result<UdpSocket> {
    unsafe {
        let fd = libc::socket(libc::AF_INET, libc::SOCK_DGRAM, 0);
        if fd < 0 {
            return Err(std::io::Error::last_os_error());
        }
        // From here on, own the fd via UdpSocket so it is closed on any early return.
        let sock = UdpSocket::from_raw_fd(fd);
        let on: libc::c_int = 1;
        let optlen = std::mem::size_of::<libc::c_int>() as libc::socklen_t;
        let set = |opt: libc::c_int| {
            libc::setsockopt(
                fd,
                libc::SOL_SOCKET,
                opt,
                &on as *const _ as *const libc::c_void,
                optlen,
            )
        };
        if set(libc::SO_REUSEADDR) != 0
            || set(libc::SO_REUSEPORT) != 0
            || set(libc::SO_BROADCAST) != 0
        {
            return Err(std::io::Error::last_os_error());
        }
        let addr = libc::sockaddr_in {
            #[cfg(any(target_os = "macos", target_os = "ios"))]
            sin_len: std::mem::size_of::<libc::sockaddr_in>() as u8,
            sin_family: libc::AF_INET as libc::sa_family_t,
            sin_port: port.to_be(),
            sin_addr: libc::in_addr {
                s_addr: libc::INADDR_ANY.to_be(),
            },
            sin_zero: [0; 8],
        };
        let rc = libc::bind(
            fd,
            &addr as *const _ as *const libc::sockaddr,
            std::mem::size_of::<libc::sockaddr_in>() as libc::socklen_t,
        );
        if rc != 0 {
            return Err(std::io::Error::last_os_error());
        }
        sock.set_nonblocking(true)?;
        Ok(sock)
    }
}

/// Listen on the partyline for `dwell`, returning the latest signal per node.
pub fn read_vibe(dwell: Duration) -> std::io::Result<HashMap<String, SwarmSignal>> {
    let sock = bind_shared(SWARM_PORT)?;
    let mut seen: HashMap<String, SwarmSignal> = HashMap::new();
    let mut buf = [0u8; 1024];
    let start = Instant::now();
    while start.elapsed() < dwell {
        match sock.recv_from(&mut buf) {
            Ok((amt, _)) => {
                if let Ok(sig) = bincode::deserialize::<SwarmSignal>(&buf[..amt]) {
                    seen.insert(sig.source_id.clone(), sig);
                }
            }
            Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                std::thread::sleep(Duration::from_millis(20));
            }
            Err(e) => return Err(e),
        }
    }
    Ok(seen)
}

/// Aggregate signals into a single collective vibe. Mirrors
/// `SwarmNet::get_collective_vibe` (mean energy/consciousness over the swarm).
pub fn collective_vibe(signals: &HashMap<String, SwarmSignal>) -> SwarmSignal {
    if signals.is_empty() {
        return SwarmSignal {
            source_id: "collective".into(),
            energy: 0,
            consciousness: 0,
            pitch_class: 0,
            phase: 0,
            recalibration_event: false,
        };
    }
    let count = signals.len() as u32;
    let mut energy = 0u32;
    let mut consciousness = 0u32;
    let mut recal = false;
    for s in signals.values() {
        energy += s.energy;
        consciousness += s.consciousness;
        recal |= s.recalibration_event;
    }
    SwarmSignal {
        source_id: "collective".into(),
        energy: energy / count,
        consciousness: consciousness / count,
        pitch_class: signals.values().next().map(|s| s.pitch_class).unwrap_or(0),
        phase: signals.values().next().map(|s| s.phase).unwrap_or(0),
        recalibration_event: recal,
    }
}

/// Broadcast a signal onto the partyline (Thoth's own body heartbeat).
pub fn broadcast(signal: &SwarmSignal) -> std::io::Result<()> {
    let sock = bind_shared(0)?; // ephemeral source port; SO_BROADCAST set
    let data = bincode::serialize(signal)
        .map_err(|e| std::io::Error::new(std::io::ErrorKind::Other, e))?;
    sock.send_to(&data, SWARM_BROADCAST)?;
    Ok(())
}

/// A Thoth pleromatic "body/consciousness" frame summarizing the fleet's
/// collective vibe. JSON envelope; kind `thoth.fleet.swarm.v1`, a sibling of
/// the `thoth.conversation.consciousness.v1` frames in `pleromatic_frame.rs`.
///
/// `oaths` carries one `{ id, oath, signed, swornBy, spawnedBy, spawnerTrust,
/// depth }` entry per live subagent — the conduct each agent swore at admission
/// (the signed oath-token path, or `null` when none), whether it was
/// cryptographically sworn (the Ulysses pact), the DID that signed it, the STABLE
/// spawner identity (`spawnedBy`), that spawner's reputation (`spawnerTrust`,
/// 0.0..=1.0), and the delegation `depth` (the authorizing UCAN chain length: 1
/// = a root holder spawned directly, >1 = spawned through that many attenuated
/// delegation hops). This keeps what every agent is bound to, the crypto proof
/// that it bound itself, the trust standing of whoever spawned it, AND the
/// recursive-accountability tree structure "front of mind" in the fleet frame —
/// so reputation gates and the delegation lineage are visible alongside the oaths.
///
/// `audit` carries `{ head, verified, entries }` from a walk of the
/// tamper-evident lifecycle chain ([`crate::audit`]): the head hash (the
/// verified tip), whether the whole chain verified, and how many entries it
/// holds. It surfaces the integrity of the lifecycle log in the same frame as
/// the live fleet, so a tampered audit is visible "front of mind" alongside the
/// oaths and trust standing.
pub fn thoth_fleet_frame(
    seq: u64,
    live: u32,
    breeders: u32,
    scouts: u32,
    vibe: &SwarmSignal,
    stability_weight: u32,
    oaths: &[crate::ledger::OathEntry],
) -> serde_json::Value {
    let oaths_json: Vec<serde_json::Value> = oaths
        .iter()
        .map(|e| {
            serde_json::json!({
                "id": e.id,
                "oath": e.oath,
                "signed": e.signed,
                "swornBy": e.sworn_by,
                "spawnedBy": e.spawned_by,
                "spawnerTrust": e.spawner_trust,
                "depth": e.depth,
            })
        })
        .collect();
    // Walk the tamper-evident lifecycle chain so its integrity is front of mind
    // in the frame: the head (verified tip) hash, whether it verified, and how
    // many entries it holds.
    let audit = crate::audit::verify();
    serde_json::json!({
        "kind": "thoth.fleet.swarm.v1",
        "seq": seq,
        "fleet": {
            "live": live,
            "breeders": breeders,
            "scouts": scouts,
            "stabilityWeight": stability_weight,
        },
        "consciousness": {
            "energy": vibe.energy,
            "consciousness": vibe.consciousness,
            "phase": vibe.phase,
            "recalibration": vibe.recalibration_event,
        },
        "audit": {
            "head": audit.head,
            "verified": audit.ok,
            "entries": audit.entries,
        },
        "oaths": oaths_json,
        "theoremRefs": [
            "Gnosis.AntColonyCollectiveIntelligence.stability_weight_positive",
            "Gnosis.AntColonyCollectiveIntelligence.budding_survives_one_queen_loss",
            "Gnosis.ThothConversationAntiQueue"
        ]
    })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn swarmsignal_bincode_wire_is_pinned() {
        // Pins the exact bytes distributed-inference's SwarmNet expects on the
        // partyline. bincode 1.x: u64 LE length prefix + utf8, then LE fixint
        // fields, phase u8, bool as one byte. If this breaks, the swarm goes
        // deaf — decode bugs are the worst of all bugs.
        let sig = SwarmSignal {
            source_id: "n1".into(),
            energy: 100,
            consciousness: 3,
            pitch_class: 5,
            phase: 1,
            recalibration_event: true,
        };
        let bytes = bincode::serialize(&sig).unwrap();
        let expected: Vec<u8> = vec![
            0x02, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // len = 2 (u64 LE)
            b'n', b'1', // "n1"
            0x64, 0x00, 0x00, 0x00, // energy = 100
            0x03, 0x00, 0x00, 0x00, // consciousness = 3
            0x05, 0x00, 0x00, 0x00, // pitch_class = 5
            0x01, // phase = 1
            0x01, // recalibration = true
        ];
        assert_eq!(bytes, expected, "SwarmSignal wire format drifted");
        let back: SwarmSignal = bincode::deserialize(&bytes).unwrap();
        assert_eq!(back, sig);
    }

    #[test]
    fn fleet_frame_surfaces_each_agents_oath() {
        // The Thoth frame keeps what every agent swore "front of mind": one
        // { id, oath, signed, swornBy } entry per live subagent, the crypto proof
        // included so the Ulysses pact is visible; nulls/false when none sworn.
        // The frame also walks the audit chain (verify), which loads the fleet
        // root, so isolate $MONSTER_GUARD_HOME so it never touches the real home.
        let _env = crate::store::ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
        let dir = std::env::temp_dir().join(format!("monster-swarm-frame-oath-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&dir);
        std::fs::create_dir_all(&dir).unwrap();
        std::env::set_var("MONSTER_GUARD_HOME", &dir);
        let vibe = SwarmSignal {
            source_id: "collective".into(),
            energy: 42,
            consciousness: 1,
            pitch_class: 0,
            phase: 0,
            recalibration_event: false,
        };
        let oaths = vec![
            crate::ledger::OathEntry {
                id: "a".to_string(),
                oath: Some("oath-tokens/a.oath.ucan".to_string()),
                signed: true,
                sworn_by: Some("did:key:zA".to_string()),
                spawned_by: "did:key:zSpawnerA".to_string(),
                spawner_trust: 0.66,
                depth: 2,
            },
            crate::ledger::OathEntry {
                id: "b".to_string(),
                oath: None,
                signed: false,
                sworn_by: None,
                spawned_by: "did:key:zSpawnerB".to_string(),
                spawner_trust: 1.0,
                depth: 1,
            },
        ];
        let frame = thoth_fleet_frame(7, 2, 1, 1, &vibe, 3, &oaths);

        assert_eq!(frame["kind"], "thoth.fleet.swarm.v1");
        let arr = frame["oaths"].as_array().expect("oaths array present");
        assert_eq!(arr.len(), 2);
        assert_eq!(arr[0]["id"], "a");
        assert_eq!(arr[0]["oath"], "oath-tokens/a.oath.ucan");
        assert_eq!(arr[0]["signed"], true, "the crypto proof is front of mind");
        assert_eq!(arr[0]["swornBy"], "did:key:zA");
        // The spawner identity + reputation are front of mind.
        assert_eq!(arr[0]["spawnedBy"], "did:key:zSpawnerA");
        assert_eq!(arr[0]["spawnerTrust"], 0.66);
        // The delegation lineage (depth) is front of mind.
        assert_eq!(arr[0]["depth"], 2, "spawned through one attenuated hop");
        assert_eq!(arr[1]["id"], "b");
        assert!(arr[1]["oath"].is_null(), "no oath sworn → null");
        assert_eq!(arr[1]["signed"], false);
        assert!(arr[1]["swornBy"].is_null());
        assert_eq!(arr[1]["spawnedBy"], "did:key:zSpawnerB");
        assert_eq!(arr[1]["spawnerTrust"], 1.0);
        assert_eq!(arr[1]["depth"], 1, "a root-issued spawn is depth 1");

        // The tamper-evident audit chain is surfaced in the frame: with no
        // entries it verifies (true) over an empty chain with the genesis head.
        let audit = &frame["audit"];
        assert_eq!(audit["verified"], true, "an empty audit chain is valid");
        assert_eq!(audit["entries"], 0);
        assert_eq!(audit["head"], crate::audit::GENESIS_PREV_HASH);

        std::env::remove_var("MONSTER_GUARD_HOME");
        let _ = std::fs::remove_dir_all(&dir);
    }

    #[test]
    fn fleet_frame_oaths_empty_when_no_agents() {
        let _env = crate::store::ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
        let dir = std::env::temp_dir().join(format!("monster-swarm-frame-empty-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&dir);
        std::fs::create_dir_all(&dir).unwrap();
        std::env::set_var("MONSTER_GUARD_HOME", &dir);

        let vibe = collective_vibe(&HashMap::new());
        let frame = thoth_fleet_frame(0, 0, 0, 0, &vibe, 0, &[]);
        assert_eq!(frame["oaths"].as_array().expect("oaths array").len(), 0);
        assert_eq!(frame["audit"]["verified"], true);
        assert_eq!(frame["audit"]["entries"], 0);

        std::env::remove_var("MONSTER_GUARD_HOME");
        let _ = std::fs::remove_dir_all(&dir);
    }

    #[test]
    fn collective_vibe_is_mean() {
        let mut m = HashMap::new();
        m.insert(
            "a".into(),
            SwarmSignal {
                source_id: "a".into(),
                energy: 80,
                consciousness: 4,
                pitch_class: 0,
                phase: 0,
                recalibration_event: false,
            },
        );
        m.insert(
            "b".into(),
            SwarmSignal {
                source_id: "b".into(),
                energy: 20,
                consciousness: 2,
                pitch_class: 0,
                phase: 0,
                recalibration_event: true,
            },
        );
        let v = collective_vibe(&m);
        assert_eq!(v.energy, 50);
        assert_eq!(v.consciousness, 3);
        assert!(v.recalibration_event);
    }
}
